// AUTO-GENERATED DRAFT SCREEN: CryptoIndexFundScreen
import React, { useState, useEffect } from 'react';
import { useQuery } from '@tanstack/react-query'; // Placeholder for tRPC hook integration
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Skeleton } from '@/components/ui/skeleton';
import { Alert, AlertDescription, AlertTitle } from '@/components/ui/alert';
import { SunIcon, MoonIcon } from '@radix-ui/react-icons';
import { Button } from '@/components/ui/button';

interface Asset {
  name: string;
  symbol: string;
  price: number;
  allocation: number;
}

interface IndexFundData {
  currentValue: number;
  dailyChange: number;
  assets: Asset[];
}

// Placeholder for tRPC client and query
// In a real application, this would be generated by tRPC
const trpc = {
  indexFund: {
    getData: {
      useQuery: (options?: any) => {
        // Simulate data fetching with a delay
        return useQuery<IndexFundData>({
          queryKey: ['indexFundData'],
          queryFn: async () => {
            await new Promise(resolve => setTimeout(resolve, 1500));
            if (Math.random() < 0.1) {
              throw new Error('Failed to fetch index fund data');
            }
            return {
              currentValue: 12345.67,
              dailyChange: 0.025,
              assets: [
                { name: 'Bitcoin', symbol: 'BTC', price: 60000, allocation: 0.5 },
                { name: 'Ethereum', symbol: 'ETH', price: 4000, allocation: 0.3 },
                { name: 'Solana', symbol: 'SOL', price: 150, allocation: 0.2 },
              ],
            };
          },
          ...options
        });
      },
    },
  },
};

const CryptoIndexFundScreen: React.FC = () => {
  const [isDarkTheme, setIsDarkTheme] = useState(false);

  useEffect(() => {
    document.documentElement.classList.toggle('dark', isDarkTheme);
  }, [isDarkTheme]);

  const { data, isLoading, isError, error, refetch } = trpc.indexFund.getData.useQuery();

  const toggleTheme = () => {
    setIsDarkTheme(prev => !prev);
  };

  if (isLoading) {
    return (
      <div className="p-4 space-y-4">
        <Skeleton className="h-10 w-1/2" />
        <Skeleton className="h-6 w-1/4" />
        <Skeleton className="h-40 w-full" />
        <Skeleton className="h-20 w-full" />
      </div>
    );
  }

  if (isError) {
    return (
      <div className="p-4">
        <Alert variant="destructive" role="alert" aria-live="assertive">
          <AlertTitle>Error</AlertTitle>
          <AlertDescription>Failed to load index fund data: {error?.message}</AlertDescription>
          <Button onClick={() => refetch()} className="mt-2">Retry</Button>
        </Alert>
      </div>
    );
  }

  return (
    <div className={`min-h-screen bg-background text-foreground ${isDarkTheme ? 'dark' : ''}`}>
      <div className="container mx-auto p-4">
        <div className="flex justify-between items-center mb-6">
          <h1 className="text-3xl font-bold" tabIndex={0}>SKYCOIN4444 Index Fund</h1>
          <Button
            variant="outline"
            size="icon"
            onClick={toggleTheme}
            aria-label={isDarkTheme ? 'Switch to light theme' : 'Switch to dark theme'}
          >
            {isDarkTheme ? <SunIcon className="h-[1.2rem] w-[1.2rem]" /> : <MoonIcon className="h-[1.2rem] w-[1.2rem]" />}
          </Button>
        </div>

        <Card className="mb-6">
          <CardHeader>
            <CardTitle tabIndex={0}>Fund Overview</CardTitle>
          </CardHeader>
          <CardContent>
            <p className="text-2xl font-semibold mb-2" tabIndex={0}>Current Value: ${data?.currentValue.toLocaleString()}</p>
            <p className={`text-lg ${data && data.dailyChange >= 0 ? 'text-green-500' : 'text-red-500'}`} tabIndex={0}>
              Daily Change: {(data?.dailyChange * 100)?.toFixed(2)}%
            </p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader>
            <CardTitle tabIndex={0}>Asset Allocation</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-2">
              {data?.assets.map((asset, index) => (
                <div key={asset.symbol} className="flex justify-between items-center py-2 border-b last:border-b-0">
                  <span className="font-medium" tabIndex={0}>{asset.name} ({asset.symbol})</span>
                  <span tabIndex={0}>${asset.price.toLocaleString()} ({ (asset.allocation * 100).toFixed(2)}%)</span>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default CryptoIndexFundScreen;
